class TagCategorySystem{constructor(options={}){this.options={container:'.tag-category-system',postsContainer:'.post-list,.post-grid',enableFilters:true,enableSorting:true,enableSearch:true,animations:true,...options};this.allPosts=[];this.filteredPosts=[];this.activeFilters=new Set();this.activeSort='date-desc';this.searchTerm='';this.init();}init(){this.container=document.querySelector(this.options.container);this.postsContainer=document.querySelector(this.options.postsContainer);if(!this.container)return;this.extractPostsData();this.extractTagsAndCategories();this.render();this.bindEvents();this.applyFiltersAndSort();}extractPostsData(){const postElements=document.querySelectorAll('.post');postElements.forEach(post=>{const title=post.querySelector('.post-title');const date=post.querySelector('.post-date');const excerpt=post.querySelector('.post-excerpt');const tags=post.querySelectorAll('.tag');const categories=post.querySelectorAll('.category');this.allPosts.push({element:post,title:title ? title.textContent.trim():'',date:date ? new Date(date.getAttribute('datetime')||date.textContent):new Date(),excerpt:excerpt ? excerpt.textContent.trim():'',tags:Array.from(tags).map(tag=>tag.textContent.trim()),categories:Array.from(categories).map(cat=>cat.textContent.trim()),url:post.querySelector('a')? post.querySelector('a').href:''});});this.filteredPosts=[...this.allPosts];}extractTagsAndCategories(){const tagCounts={};const categoryCounts={};this.allPosts.forEach(post=>{post.tags.forEach(tag=>{tagCounts[tag]=(tagCounts[tag]||0)+1;});post.categories.forEach(category=>{categoryCounts[category]=(categoryCounts[category]||0)+1;});});this.tags=Object.entries(tagCounts).map(([name,count])=>({name,count})).sort((a,b)=>b.count-a.count);this.categories=Object.entries(categoryCounts).map(([name,count])=>({name,count})).sort((a,b)=>b.count-a.count);}render(){this.container.innerHTML=`<div class="tag-category-container"><div class="tag-category-header"><h3 data-i18n="tags.title">Filter&Sort</h3><div class="tag-category-actions"><button class="btn btn-secondary btn-sm clear-filters" data-i18n="tags.clear_all">Clear All</button><button class="btn btn-secondary btn-sm toggle-view" data-i18n="tags.toggle_view">Toggle View</button></div></div>${this.options.enableSearch ? this.renderSearchInput():''}<div class="tag-category-sections"><div class="tag-category-section"><h4 data-i18n="tags.categories">Categories</h4><div class="tag-list category-list">${this.renderFilterItems(this.categories,'category')}</div></div><div class="tag-category-section"><h4 data-i18n="tags.tags">Tags</h4><div class="tag-list tag-filter-list">${this.renderFilterItems(this.tags,'tag')}</div></div></div>${this.options.enableSorting ? this.renderSortOptions():''}<div class="tag-category-stats"><span class="stats-text" data-i18n="tags.showing_count">Showing<span class="stats-count">${this.filteredPosts.length}</span>of ${this.allPosts.length}posts</span></div></div>`;}renderSearchInput(){return `<div class="search-container"><div class="search-input-wrapper"><input type="text" class="search-input" placeholder="Search posts..." data-i18n-placeholder="tags.search_placeholder"/><button class="search-clear" aria-label="Clear search"><span class="search-icon">✕</span></button></div></div>`;}renderFilterItems(items,type){return items.map(item=>`<button class="tag-filter ${type}-filter" data-${type}="${item.name}" data-count="${item.count}"><span class="tag-filter-name">${item.name}</span><span class="tag-filter-count">${item.count}</span></button>`).join('');}renderSortOptions(){return `<div class="sort-container"><label for="sort-select" data-i18n="tags.sort_by">Sort by:</label><select id="sort-select" class="sort-select"><option value="date-desc" data-i18n="sort.newest_first">Newest First</option><option value="date-asc" data-i18n="sort.oldest_first">Oldest First</option><option value="title-asc" data-i18n="sort.title_asc">Title(A-Z)</option><option value="title-desc" data-i18n="sort.title_desc">Title(Z-A)</option><option value="relevance" data-i18n="sort.relevance">Relevance</option></select></div>`;}bindEvents(){this.container.addEventListener('click',(e)=>{const filter=e.target.closest('.tag-filter');if(filter){e.preventDefault();this.toggleFilter(filter);}if(e.target.classList.contains('clear-filters')){this.clearAllFilters();}if(e.target.classList.contains('toggle-view')){this.toggleView();}});const searchInput=this.container.querySelector('.search-input');if(searchInput){searchInput.addEventListener('input',(e)=>{this.searchTerm=e.target.value.toLowerCase();this.applyFiltersAndSort();});}const searchClear=this.container.querySelector('.search-clear');if(searchClear){searchClear.addEventListener('click',()=>{searchInput.value='';this.searchTerm='';this.applyFiltersAndSort();});}const sortSelect=this.container.querySelector('#sort-select');if(sortSelect){sortSelect.addEventListener('change',(e)=>{this.activeSort=e.target.value;this.applyFiltersAndSort();});}this.container.addEventListener('keydown',(e)=>{if(e.key==='Escape'){this.clearAllFilters();searchInput.value='';this.searchTerm='';this.applyFiltersAndSort();}});}toggleFilter(filterElement){const name=filterElement.dataset.tag||filterElement.dataset.category;const type=filterElement.dataset.tag ? 'tag':'category';const filterKey=`${type}:${name}`;if(this.activeFilters.has(filterKey)){this.activeFilters.delete(filterKey);filterElement.classList.remove('active');}else{this.activeFilters.add(filterKey);filterElement.classList.add('active');}this.applyFiltersAndSort();}clearAllFilters(){this.activeFilters.clear();this.container.querySelectorAll('.tag-filter').forEach(filter=>{filter.classList.remove('active');});const searchInput=this.container.querySelector('.search-input');if(searchInput){searchInput.value='';this.searchTerm='';}this.applyFiltersAndSort();}toggleView(){const currentView=this.postsContainer.classList.contains('post-grid')? 'grid':'list';if(currentView==='list'){this.postsContainer.classList.remove('post-list');this.postsContainer.classList.add('post-grid');}else{this.postsContainer.classList.remove('post-grid');this.postsContainer.classList.add('post-list');}localStorage.setItem('preferred-view',currentView==='list' ? 'grid':'list');}applyFiltersAndSort(){this.filteredPosts=this.allPosts.filter(post=>{if(this.searchTerm){const searchMatch=post.title.toLowerCase().includes(this.searchTerm)||post.excerpt.toLowerCase().includes(this.searchTerm)||post.tags.some(tag=>tag.toLowerCase().includes(this.searchTerm))||post.categories.some(cat=>cat.toLowerCase().includes(this.searchTerm));if(!searchMatch)return false;}if(this.activeFilters.size>0){const matchingTags=post.tags.filter(tag=>this.activeFilters.has(`tag:${tag}`));const matchingCategories=post.categories.filter(category=>this.activeFilters.has(`category:${category}`));if(matchingTags.length===0&&matchingCategories.length===0){return false;}}return true;});this.sortPosts();this.updatePostDisplay();this.updateStats();}sortPosts(){switch(this.activeSort){case 'date-desc':this.filteredPosts.sort((a,b)=>b.date-a.date);break;case 'date-asc':this.filteredPosts.sort((a,b)=>a.date-b.date);break;case 'title-asc':this.filteredPosts.sort((a,b)=>a.title.localeCompare(b.title));break;case 'title-desc':this.filteredPosts.sort((a,b)=>b.title.localeCompare(a.title));break;case 'relevance':this.sortByRelevance();break;}}sortByRelevance(){if(!this.searchTerm){this.filteredPosts.sort((a,b)=>b.date-a.date);return;}this.filteredPosts.forEach(post=>{let score=0;if(post.title.toLowerCase().includes(this.searchTerm)){score+=100;}post.tags.forEach(tag=>{if(tag.toLowerCase().includes(this.searchTerm)){score+=50;}});post.categories.forEach(category=>{if(category.toLowerCase().includes(this.searchTerm)){score+=30;}});if(post.excerpt.toLowerCase().includes(this.searchTerm)){score+=10;}post.relevanceScore=score;});this.filteredPosts.sort((a,b)=>(b.relevanceScore||0)-(a.relevanceScore||0));}updatePostDisplay(){const posts=this.filteredPosts;if(this.options.animations){this.allPosts.forEach(post=>{post.element.style.opacity='0';post.element.style.transform='translateY(20px)';});setTimeout(()=>{this.allPosts.forEach(post=>{post.element.style.display='none';});posts.forEach((post,index)=>{post.element.style.display='';post.element.style.opacity='0';post.element.style.transform='translateY(20px)';setTimeout(()=>{post.element.style.opacity='1';post.element.style.transform='translateY(0)';},index*50);});},300);}else{this.allPosts.forEach(post=>{post.element.style.display='none';});posts.forEach(post=>{post.element.style.display='';});}}updateStats(){const statsCount=this.container.querySelector('.stats-count');if(statsCount){statsCount.textContent=this.filteredPosts.length;}const clearButton=this.container.querySelector('.clear-filters');if(clearButton){const hasActiveFilters=this.activeFilters.size>0||this.searchTerm;clearButton.disabled=!hasActiveFilters;clearButton.textContent=this.activeFilters.size>0 ? `Clear(${this.activeFilters.size})`:'Clear All';}}}document.addEventListener('DOMContentLoaded',()=>{const container=document.querySelector('.tag-category-system');if(container){window.tagCategorySystem=new TagCategorySystem({container:'.tag-category-system',postsContainer:'.post-list,.post-grid',enableFilters:true,enableSorting:true,enableSearch:true,animations:true});}});if(typeof module!=='undefined'&&module.exports){module.exports=TagCategorySystem;}